// Some portions generated by Codex

package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class TupleSketchOpsTest {

	@Test
	void directLookupHandlesLongMinValueInIntersectionProducts() {
		int k = 64;
		var left = TupleSketchOps.newSketch(k);
		var right = TupleSketchOps.newSketch(k);
		TupleSketchOps.update(left, Long.MIN_VALUE, 2.0d);
		TupleSketchOps.update(right, Long.MIN_VALUE, 3.0d);
		TupleSketchOps.update(right, 42L, 11.0d);

		double productSum = TupleSketchOps.estimateIntersectionProductSum(left.compact(), right.compact(), k);

		assertEquals(6.0d, productSum, 0.0d,
				"Direct tuple-sketch lookup must not reserve Long.MIN_VALUE as an empty-slot sentinel");
	}

	@Test
	void subtractPositiveHandlesLongMinValueInTombstoneSketches() {
		int k = 64;
		var additions = TupleSketchOps.newSketch(k);
		var deletions = TupleSketchOps.newSketch(k);
		TupleSketchOps.update(additions, Long.MIN_VALUE, 3.0d);
		TupleSketchOps.update(additions, 17L, 1.0d);
		TupleSketchOps.update(deletions, Long.MIN_VALUE, 1.0d);

		var net = TupleSketchOps.subtractPositive(additions.compact(), deletions.compact(), k);

		assertEquals(3.0d, TupleSketchOps.estimatePositiveSum(net), 0.0d,
				"Deletion overlays must correctly retain Long.MIN_VALUE entries after subtraction");
	}
}
